prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?gw ?gwName ?taskCount WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  ?model tai:belongsTo ?org .

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .

  ?gw a bboExt:ParallelGateway .
  ?gw tai:belongsTo ?choreo .

  OPTIONAL { ?gw bbo:name ?gwName . }

  {
    SELECT ?choreo (COUNT(DISTINCT ?task) AS ?taskCount) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task tai:belongsTo ?choreo .
    }
    GROUP BY ?choreo
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?choreoName (COUNT(DISTINCT ?pg) AS ?parallelGateways) WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2d887704e5324e6bb2126cef061e50e9" .
  }
  UNION
  {
    ?model tai:originalId "2d887704e5324e6bb2126cef061e50e9" .
  }

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  OPTIONAL { ?pg a bboExt:ParallelGateway ; tai:belongsTo ?choreo . }

  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?parallelGateways)
LIMIT 25
